 3→internal class FolderSettingsWriter {
 4→    fun write(editor: StorageEditor, accountUuid: String, folder: ValidatedSettings.Folder) {
 5→        // Convert folder settings to the string representation used in preference storage
 6→        val stringSettings = FolderSettingsDescriptions.convert(folder.settings)
 7→
 8→        // Write folder settings
 9→        val prefix = "$accountUuid.${folder.name}."
10→        for ((folderKey, value) in stringSettings) {
11→            val key = prefix + folderKey
12→            editor.putStringWithLogging(key, value)
13→        }
14→    }
15→}
