    private fun applyManualSelectionForImportedFolders(
        importedSettings: SettingsMap,
        validatedSettings: InternalSettingsMap,
    ): InternalSettingsMap {
        val selectionOverrides = mapOf(
            "archiveFolderName" to "archiveFolderSelection",
            "draftsFolderName" to "draftsFolderSelection",
            "sentFolderName" to "sentFolderSelection",
            "spamFolderName" to "spamFolderSelection",
            "trashFolderName" to "trashFolderSelection",
        )

        val updatedSettings = validatedSettings.toMutableMap()

        for ((folderNameKey, selectionKey) in selectionOverrides) {
            if (shouldForceManualSelection(importedSettings, folderNameKey, selectionKey)) {
                updatedSettings[selectionKey] = SpecialFolderSelection.MANUAL
            }
        }

        return updatedSettings
    }

    private fun shouldForceManualSelection(
        importedSettings: SettingsMap,
        folderNameKey: String,
        selectionKey: String,
    ): Boolean {
        if (selectionKey in importedSettings) {
            return false
        }

        val folderName = importedSettings[folderNameKey]?.trim()
        if (folderName.isNullOrEmpty()) {
            return false
        }

