316→
317→        IntegerResourceSetting(int defaultValue, int resId) {
318→            super(defaultValue);
319→
320→            Map<Integer, String> mapping = new HashMap<>();
321→            String[] values = context.getResources().getStringArray(resId);
322→            for (String value : values) {
323→                int intValue = Integer.parseInt(value);
324→                mapping.put(intValue, value);
325→            }
326→            this.mapping = Collections.unmodifiableMap(mapping);
327→        }
328→
329→        @Override
330→        protected Map<Integer, String> getMapping() {
331→            return mapping;
332→        }
333→
334→        @Override
335→        public Integer fromString(String value) throws InvalidSettingValueException {
336→            try {
337→                return Integer.parseInt(value);
338→            } catch (NumberFormatException e) {
339→                throw new InvalidSettingValueException();
340→            }
341→        }
342→    }
